const staticData = $getWorkflowStaticData('global');
const config = $('Configuration Tado').first().json;

const CLIENT_ID = config.CLIENT_ID;
const REFRESH_TOKEN = staticData.tado_refresh_token;

if (!REFRESH_TOKEN) {
  return [{
    auth_ok: false,
    auth_reason: 'missing_refresh_token'
  }];
}

try {
  const authResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://login.tado.com/oauth2/token',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: `client_id=${encodeURIComponent(CLIENT_ID)}&grant_type=refresh_token&refresh_token=${encodeURIComponent(REFRESH_TOKEN)}`,
  });

  if (!authResponse.access_token) {
    return [{
      auth_ok: false,
      auth_reason: 'no_access_token_returned'
    }];
  }

  staticData.tado_access_token = authResponse.access_token;

  if (authResponse.refresh_token) {
    staticData.tado_refresh_token = authResponse.refresh_token;
  }

  return [{
    auth_ok: true,
    access_token: authResponse.access_token
  }];

} catch (error) {
  return [{
    auth_ok: false,
    auth_reason: 'refresh_failed',
    auth_error: error.message
  }];
}

const tado = $('Lire état zone Tado').first().json;
const meteo = $('Lire météo').first().json;

const power = tado.setting?.power ?? 'OFF';
const tempInt = tado.sensorDataPoints?.insideTemperature?.celsius ?? null;

// Si le chauffage est OFF, on considère une consigne mini à 5
const currentSetpoint = power === 'ON'
  ? (tado.setting?.temperature?.celsius ?? 5)
  : 5;

const tempExt = meteo.main?.temp ?? null;

if (tempInt === null || tempExt === null) {
  throw new Error("Température intérieure ou extérieure introuvable.");
}

return [{
  // --- DONNÉES TADO (Intérieur) ---
  temp_interieure: tempInt,
  humidite_interieure: tado.sensorDataPoints?.humidity?.percentage ?? null,
  consigne_actuelle: currentSetpoint,
  power_actuel: power,

  // --- DÉTECTION FENÊTRE OUVERTE ---
  // Compatibilité avec plusieurs variantes possibles du state Tado
  window_open_detected: Boolean(
    (tado.openWindow && tado.openWindow !== null) ||
    tado.openWindowDetected === true ||
    (typeof tado.openWindowDetected === 'object' && tado.openWindowDetected !== null)
  ),
  window_open_raw: tado.openWindow ?? tado.openWindowDetected ?? null,

  // --- DONNÉES MÉTÉO (Extérieur) ---
  temp_exterieure: tempExt,
  nuages_pourcent: meteo.clouds?.all ?? 0,
  humidite_pourcent: meteo.main?.humidity ?? null,
  vitesse_vent_ms: meteo.wind?.speed ?? null,
  condition_meteo: meteo.weather?.[0]?.description ?? 'inconnu',
  condition_meteo_main: meteo.weather?.[0]?.main ?? 'Unknown',

  // --- LEVER / COUCHER DU SOLEIL ---
  heure_lever_soleil: meteo.sys?.sunrise
    ? new Date(meteo.sys.sunrise * 1000).toLocaleTimeString('fr-FR')
    : null,
  heure_coucher_soleil: meteo.sys?.sunset
    ? new Date(meteo.sys.sunset * 1000).toLocaleTimeString('fr-FR')
    : null
}];

const staticData = $getWorkflowStaticData('global');
const data = $json;
const meteo = $('Lire météo').first().json;
const configLogement = $('Configuration Logement').first().json;

const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();
const month = now.getMonth() + 1;
const day = now.getDay();

const tempInt = Number(data.temp_interieure);
const tempExt = Number(data.temp_exterieure);
const currentSetpoint = Number(data.consigne_actuelle);
const powerActuel = data.power_actuel;
const humiditeInt = data.humidite_interieure !== undefined ? Number(data.humidite_interieure) : null;

// Fenêtre ouverte détectée depuis le node "Fusionner données"
const windowOpenDetected = Boolean(data.window_open_detected);

// Météo enrichie pour les alertes humidité
const outsideHumidity = Number(meteo.main?.humidity ?? 0);
const windSpeed = Number(meteo.wind?.speed ?? 0);
const weatherMain = String(meteo.weather?.[0]?.main ?? '').toLowerCase();
const weatherDescription = String(meteo.weather?.[0]?.description ?? '').toLowerCase();

const isRainyLike =
  ['rain', 'drizzle', 'thunderstorm'].includes(weatherMain) ||
  weatherDescription.includes('pluie') ||
  weatherDescription.includes('averse') ||
  weatherDescription.includes('orage');

const isSnowLike =
  weatherMain === 'snow' ||
  weatherDescription.includes('neige');

// Présence par défaut configurable
const presence = typeof data.presence === 'boolean'
  ? data.presence
  : Boolean(configLogement.DEFAULT_PRESENCE);

// ==============================
// 1. CONFIGURATION GÉNÉRALE
// ==============================

const LAT = Number(configLogement.Lat);
const LON = Number(configLogement.Lon);

const WINDOW_AZIMUTH = Number(configLogement.AZIMUTH);
const AZIMUTH_TOLERANCE = Number(configLogement.AZIMUTH_TOLERANCE);

const TADO_MIN = Number(configLogement.Min_thérmostat);
const TADO_MAX = Number(configLogement.Max_thérmostat);

const THERMAL_INERTIA = Number(configLogement.THERMAL_INERTIA ?? 0.9);

const cloudCover = Number(meteo.clouds?.all ?? 0);

const MIN_DELTA_SETPOINT = Number(configLogement.MIN_DELTA_SETPOINT ?? 0.5);
const MIN_DELAY_MINUTES = Number(configLogement.MIN_DELAY_MINUTES ?? 25);

const OVERHEAT_LIMIT = Number(configLogement.OVERHEAT_LIMIT ?? 22.6);
const HARD_SUMMER_EXT_LIMIT = Number(configLogement.HARD_SUMMER_EXT_LIMIT ?? 25);

const WORKDAY_MORNING_HOUR = Number(configLogement.WORKDAY_MORNING_HOUR ?? 6);
const WEEKEND_MORNING_HOUR = Number(configLogement.WEEKEND_MORNING_HOUR ?? 8);
const EVENING_START_HOUR = Number(configLogement.EVENING_START_HOUR ?? 17);
const NIGHT_START_HOUR = Number(configLogement.NIGHT_START_HOUR ?? 22);
const LATE_NIGHT_START_HOUR = Number(configLogement.LATE_NIGHT_START_HOUR ?? 23);

const SUNSET_PREHEAT_WINDOW_MIN = Number(configLogement.SUNSET_PREHEAT_WINDOW_MIN ?? 90);

const SOLAR_BONUS_MAX = Number(configLogement.SOLAR_BONUS_MAX ?? 1.8);
const TREND_WEIGHT = Number(configLogement.TREND_WEIGHT ?? 0.35);

const MODE_OFF = Number(configLogement.MODE_OFF ?? 5);
const MODE_ECO_MIN = Number(configLogement.MODE_ECO_MIN ?? 6);

// ==============================
// 2. OUTILS
// ==============================

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function round1(v) {
  return Math.round(v * 10) / 10;
}

function normalizeAngle(deg) {
  let a = deg % 360;
  if (a < 0) a += 360;
  return a;
}

function angleInSector(angle, start, end) {
  const a = normalizeAngle(angle);
  const s = normalizeAngle(start);
  const e = normalizeAngle(end);

  if (s <= e) return a >= s && a <= e;
  return a >= s || a <= e;
}

function formatTadoSetpoint(val) {
  let v = clamp(val, TADO_MIN, TADO_MAX);

  if (v < 15) {
    v = Math.round(v);
  } else {
    v = Math.round(v * 2) / 2;
  }

  return clamp(v, TADO_MIN, TADO_MAX);
}

function getSeason(month) {
  if ([12, 1, 2].includes(month)) return 'winter';
  if ([3, 4, 5].includes(month)) return 'spring';
  if ([6, 7, 8].includes(month)) return 'summer';
  return 'autumn';
}

function isWeekend(day) {
  return day === 0 || day === 6;
}

function getSolarPosition(lat, lon, date) {
  const rad = Math.PI / 180;
  const days = (date.getTime() / 86400000) - 10957.5;

  const L = (280.460 + 0.9856474 * days) % 360;
  const g = ((357.528 + 0.9856003 * days) % 360) * rad;
  const lambda = (L + 1.915 * Math.sin(g) + 0.020 * Math.sin(2 * g)) * rad;
  const epsilon = (23.439 - 0.0000004 * days) * rad;

  const alpha = Math.atan2(Math.cos(epsilon) * Math.sin(lambda), Math.cos(lambda));
  const delta = Math.asin(Math.sin(epsilon) * Math.sin(lambda));

  const GMST = (18.697374558 + 24.06570982441908 * days) % 24;
  const H = (GMST * 15 + lon) * rad - alpha;
  const phi = lat * rad;

  const elevation = Math.asin(
    Math.sin(phi) * Math.sin(delta) +
    Math.cos(phi) * Math.cos(delta) * Math.cos(H)
  );

  let azimuth = Math.atan2(
    Math.sin(H),
    Math.cos(H) * Math.sin(phi) - Math.tan(delta) * Math.cos(phi)
  );

  return {
    elevation: elevation / rad,
    azimuth: normalizeAngle((azimuth / rad + 180))
  };
}

function getSolarGainScore(solar, cloudCoverPercent, windowAzimuth, toleranceDeg) {
  const azMin = windowAzimuth - toleranceDeg;
  const azMax = windowAzimuth + toleranceDeg;

  const sunFacingWindow = angleInSector(solar.azimuth, azMin, azMax);
  const hasEnoughElevation = solar.elevation > 7;
  const cloudFactor = clamp(1 - (cloudCoverPercent / 100), 0, 1);

  if (!sunFacingWindow || !hasEnoughElevation) {
    return {
      sunFacingWindow,
      hasEnoughElevation,
      gainScore: 0
    };
  }

  const elevationFactor = clamp((solar.elevation - 7) / 35, 0, 1);
  const gainScore = elevationFactor * cloudFactor;

  return {
    sunFacingWindow,
    hasEnoughElevation,
    gainScore: clamp(gainScore, 0, 1)
  };
}

// ==============================
// 3. CONTEXTE
// ==============================

const season = getSeason(month);
const weekend = isWeekend(day);
const morningStart = weekend ? WEEKEND_MORNING_HOUR : WORKDAY_MORNING_HOUR;

let phase = 'day';
if (hour >= LATE_NIGHT_START_HOUR || hour < morningStart) {
  phase = 'late_night';
} else if (hour >= morningStart && hour < 9) {
  phase = 'morning';
} else if (hour >= 9 && hour < EVENING_START_HOUR) {
  phase = 'day';
} else if (hour >= EVENING_START_HOUR && hour < NIGHT_START_HOUR) {
  phase = 'evening';
} else {
  phase = 'night';
}

const solar = getSolarPosition(LAT, LON, now);
const solarInfo = getSolarGainScore(solar, cloudCover, WINDOW_AZIMUTH, AZIMUTH_TOLERANCE);
const solarGainScore = solarInfo.gainScore;

// Utilisation des données directes d'OpenWeatherMap pour le coucher du soleil
const sunsetTimeMs = meteo.sys?.sunset ? meteo.sys.sunset * 1000 : 0;
const minutesBeforeSunset = sunsetTimeMs ? (sunsetTimeMs - now.getTime()) / 60000 : 0;

const isSunsetApproaching =
  minutesBeforeSunset > 0 &&
  minutesBeforeSunset <= SUNSET_PREHEAT_WINDOW_MIN;

const prevTempInt = staticData.prev_temp_int;
const prevTempTs = staticData.prev_temp_ts;

let tempTrendPerHour = 0;
if (typeof prevTempInt === 'number' && typeof prevTempTs === 'number') {
  const elapsedHours = (Date.now() - prevTempTs) / 3600000;
  if (elapsedHours > 0.2 && elapsedHours < 6) {
    tempTrendPerHour = (tempInt - prevTempInt) / elapsedHours;
  }
}

staticData.prev_temp_int = tempInt;
staticData.prev_temp_ts = Date.now();

const solarThermalBonus = solarGainScore * SOLAR_BONUS_MAX * THERMAL_INERTIA;
const effectiveIndoorTemp = tempInt + solarThermalBonus + (tempTrendPerHour * TREND_WEIGHT);

// ==============================
// 4. CONFORT CIBLE DYNAMIQUE
// ==============================

function getBaseComfortTarget(season, phase, weekend, presence) {
  const tables = {
    winter: {
      late_night: presence ? 18.0 : 17.0,
      morning: weekend ? 21.5 : 21.2,
      day: presence ? 21.5 : 18.5,
      evening: 21.5,
      night: presence ? 19.0 : 17.5
    },
    spring: {
      late_night: presence ? 17.8 : 17.0,
      morning: weekend ? 21.0 : 20.8,
      day: presence ? 21.0 : 18.0,
      evening: 21.0,
      night: presence ? 18.7 : 17.3
    },
    summer: {
      late_night: 17.5,
      morning: 20.0,
      day: presence ? 20.5 : 18.0,
      evening: 20.5,
      night: 18.0
    },
    autumn: {
      late_night: presence ? 18.0 : 17.1,
      morning: weekend ? 21.3 : 21.0,
      day: presence ? 21.2 : 18.3,
      evening: 21.2,
      night: presence ? 18.8 : 17.4
    }
  };

  return tables[season][phase];
}

let dynamicComfort = getBaseComfortTarget(season, phase, weekend, presence);

if (tempExt <= 2) dynamicComfort += 0.3;
if (tempExt <= -2) dynamicComfort += 0.2;
if (tempExt >= 16) dynamicComfort -= 0.4;
if (tempExt >= 20) dynamicComfort -= 0.4;

if (solarGainScore >= 0.55) dynamicComfort -= 0.8;
else if (solarGainScore >= 0.30) dynamicComfort -= 0.4;

if (isSunsetApproaching && solarGainScore > 0.15 && phase === 'day') {
  dynamicComfort += 0.3;
}

dynamicComfort = clamp(dynamicComfort, 17.0, 22.0);

// ==============================
// 5. DÉCISION PRINCIPALE
// ==============================

const scriptLastForcedOff = staticData.script_last_mode === 'OFF';
let target = currentSetpoint;
let targetMode = 'SETPOINT';
let reason = 'maintien';

if (windowOpenDetected) {
  target = MODE_ECO_MIN; // 6°C
  targetMode = 'WINDOW_OPEN_ECO';
  reason = 'fenetre_ouverte';
}
else if (powerActuel === 'OFF' && !scriptLastForcedOff) {
  target = MODE_OFF;
  targetMode = 'MANUAL_OFF_RESPECTED';
  reason = 'desactive_manuellement';
} else {
  if (tempExt >= HARD_SUMMER_EXT_LIMIT) {
    target = MODE_ECO_MIN;
    targetMode = 'ECO_MIN';
    reason = 'ete_veille';
  }

  else if (effectiveIndoorTemp >= OVERHEAT_LIMIT) {
    target = MODE_ECO_MIN;
    targetMode = 'ECO_MIN';
    reason = solarGainScore >= 0.25 ? 'surchauffe_solaire' : 'surchauffe';
  }

  else if (phase === 'late_night') {
    if (effectiveIndoorTemp < 17.3) {
      target = 18.0;
      targetMode = 'SETPOINT';
      reason = 'nuit_chauffe';
    } else if (effectiveIndoorTemp >= 18.3) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'nuit_veille';
    } else {
      target = currentSetpoint;
      targetMode = 'SETPOINT';
      reason = 'nuit_maintien';
    }
  }

  else if (phase === 'morning') {
    const gap = dynamicComfort - effectiveIndoorTemp;

    if (gap >= 1.6) {
      target = 22.0;
      reason = 'matin_rattrapage';
    } else if (gap >= 0.9) {
      target = 21.5;
      reason = 'matin_chauffe';
    } else if (gap >= 0.3) {
      target = 20.5;
      reason = 'matin_maintien_actif';
    } else if (effectiveIndoorTemp >= dynamicComfort + 0.5) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'matin_veille';
    } else {
      target = currentSetpoint;
      reason = 'matin_maintien';
    }
  }

  else if (phase === 'day') {
    const gap = dynamicComfort - effectiveIndoorTemp;

    if (solarGainScore >= 0.60 && tempInt >= 20.0) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'jour_apport_solaire_fort';
    } else if (solarGainScore >= 0.35 && gap <= 0.8) {
      target = 19.5;
      reason = 'jour_chauffe_reduite_soleil';
    } else if (gap >= 1.5) {
      target = 21.5;
      reason = 'jour_chauffe_forte';
    } else if (gap >= 0.8) {
      target = 21.0;
      reason = 'jour_chauffe';
    } else if (gap >= 0.2) {
      target = 20.0;
      reason = isSunsetApproaching ? 'anticipation_fin_soleil' : 'jour_maintien_actif';
    } else if (effectiveIndoorTemp >= dynamicComfort + 0.6) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'jour_veille';
    } else {
      target = currentSetpoint;
      reason = 'jour_maintien';
    }
  }

  else if (phase === 'evening') {
    const gap = dynamicComfort - effectiveIndoorTemp;

    if (gap >= 1.4) {
      target = 21.5;
      reason = 'soir_chauffe_forte';
    } else if (gap >= 0.7) {
      target = 21.0;
      reason = 'soir_chauffe';
    } else if (gap >= 0.2) {
      target = 20.0;
      reason = 'soir_maintien_actif';
    } else if (effectiveIndoorTemp >= dynamicComfort + 0.5) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'soir_veille';
    } else {
      target = currentSetpoint;
      reason = 'soir_maintien';
    }
  }

  else {
    if (effectiveIndoorTemp < 18.2) {
      target = 18.5;
      reason = 'nuit_tardive_chauffe';
    } else if (effectiveIndoorTemp >= 19.0) {
      target = MODE_ECO_MIN;
      targetMode = 'ECO_MIN';
      reason = 'nuit_tardive_veille';
    } else {
      target = currentSetpoint;
      reason = 'nuit_tardive_maintien';
    }
  }
}

if (targetMode !== 'MANUAL_OFF_RESPECTED' && target > MODE_ECO_MIN) {
  target = formatTadoSetpoint(target);
}

if (
  staticData.script_turned_it_off === true &&
  currentSetpoint <= MODE_ECO_MIN &&
  tempInt >= 20.3 &&
  solarGainScore > 0.15
) {
  target = MODE_ECO_MIN;
  targetMode = 'ECO_MIN';
  reason = 'inertie_post_veille';
}

if (tempTrendPerHour > 0.25 && tempInt >= dynamicComfort - 0.2 && target > MODE_ECO_MIN) {
  target = Math.min(target, 19.5);
  target = formatTadoSetpoint(target);
  reason = 'montee_naturelle_temperature';
}

if (!presence && tempInt >= 19.2 && season !== 'winter') {
  target = Math.min(target, 18.0);
  if (target > MODE_ECO_MIN) {
    target = formatTadoSetpoint(target);
    targetMode = 'SETPOINT';
  }
  reason = 'absence_mode_eco';
}

// ==============================
// 6. GESTION DE L'HUMIDITÉ
// ==============================

function getHumidityProfile(season, phase, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike) {
  const baseProfiles = {
    winter: {
      idealMin: 35,
      idealMax: 45,
      warnLow: 30,
      warnHigh: 55,
      criticalLow: 27,
      criticalHigh: 60
    },
    spring: {
      idealMin: 40,
      idealMax: 50,
      warnLow: 35,
      warnHigh: 58,
      criticalLow: 30,
      criticalHigh: 63
    },
    summer: {
      idealMin: 45,
      idealMax: 55,
      warnLow: 40,
      warnHigh: 60,
      criticalLow: 35,
      criticalHigh: 65
    },
    autumn: {
      idealMin: 40,
      idealMax: 50,
      warnLow: 35,
      warnHigh: 58,
      criticalLow: 30,
      criticalHigh: 63
    }
  };

  const profile = { ...baseProfiles[season] };

  // Hiver froid : air sec plus fréquent, mais humidité haute plus risquée
  if (season === 'winter') {
    if (tempExt <= 0) {
      profile.warnLow -= 2;
      profile.criticalLow -= 2;
      profile.warnHigh -= 3;
      profile.criticalHigh -= 3;
    }

    if (phase === 'night' || phase === 'late_night') {
      profile.warnLow -= 1;
    }
  }

  // Été chaud : moiteur plus gênante
  if (season === 'summer' && tempExt >= 26) {
    profile.warnHigh -= 2;
    profile.criticalHigh -= 2;
  }

  // Météo très humide / pluvieuse : plus strict sur humidité haute
  if (outsideHumidity >= 85 || isRainyLike) {
    profile.warnHigh -= 2;
    profile.criticalHigh -= 2;
  }

  // Neige / froid sec : on tolère un peu plus l'air sec
  if (isSnowLike || (tempExt <= 2 && outsideHumidity <= 50)) {
    profile.warnLow -= 1;
    profile.criticalLow -= 1;
  }

  // Fort vent + froid : l'air intérieur se dessèche plus vite
  if (windSpeed >= 8 && tempExt <= 8) {
    profile.warnLow -= 1;
  }

  return profile;
}

function buildHumidityAdvice(status, severity, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike) {
  if (status === 'too_humid') {
    if (isRainyLike || outsideHumidity >= 85) {
      return "Dehors l'air est déjà humide : privilégie une aération courte, la VMC ou un déshumidificateur.";
    }
    if (tempExt <= 8) {
      return "Bon moment pour aérer 5 à 10 minutes sans trop refroidir le logement.";
    }
    return "Tu peux aérer 10 minutes si l'air extérieur est plus sec, sinon privilégie la VMC.";
  }

  if (status === 'too_dry') {
    if (tempExt <= 5 || isSnowLike) {
      return "Avec le froid dehors, c'est assez classique : évite d'aérer trop longtemps et pense à humidifier légèrement l'air.";
    }
    if (windSpeed >= 8) {
      return "Le vent accentue souvent l'assèchement de l'air intérieur.";
    }
    return "Tu peux humidifier légèrement l'air : linge à sécher, bol d'eau, ou humidificateur.";
  }

  return "";
}

const seasonLabels = {
  winter: 'hiver',
  spring: 'printemps',
  summer: 'été',
  autumn: 'automne'
};

let alertMessage = null;
let sendHumAlert = false;
let humidityStatus = 'normal';
let humiditySeverity = 'none';

const humidityProfile = getHumidityProfile(
  season,
  phase,
  tempExt,
  outsideHumidity,
  windSpeed,
  isRainyLike,
  isSnowLike
);

if (humiditeInt !== null) {
  if (humiditeInt <= humidityProfile.criticalLow) {
    humidityStatus = 'too_dry';
    humiditySeverity = 'critical';
    const advice = buildHumidityAdvice(humidityStatus, humiditySeverity, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike);
    alertMessage = `🌵 Air très sec (${humiditeInt}%). En ${seasonLabels[season]}, vise plutôt ${humidityProfile.idealMin}-${humidityProfile.idealMax}%. ${advice}`;
  } else if (humiditeInt < humidityProfile.warnLow) {
    humidityStatus = 'too_dry';
    humiditySeverity = 'warning';
    const advice = buildHumidityAdvice(humidityStatus, humiditySeverity, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike);
    alertMessage = `🌵 Air un peu trop sec (${humiditeInt}%). Zone confortable : ${humidityProfile.idealMin}-${humidityProfile.idealMax}%. ${advice}`;
  } else if (humiditeInt >= humidityProfile.criticalHigh) {
    humidityStatus = 'too_humid';
    humiditySeverity = 'critical';
    const advice = buildHumidityAdvice(humidityStatus, humiditySeverity, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike);
    alertMessage = `💧 Air très humide (${humiditeInt}%). En ${seasonLabels[season]}, essaie de rester vers ${humidityProfile.idealMin}-${humidityProfile.idealMax}%. ${advice}`;
  } else if (humiditeInt > humidityProfile.warnHigh) {
    humidityStatus = 'too_humid';
    humiditySeverity = 'warning';
    const advice = buildHumidityAdvice(humidityStatus, humiditySeverity, tempExt, outsideHumidity, windSpeed, isRainyLike, isSnowLike);
    alertMessage = `💧 Air un peu trop humide (${humiditeInt}%). Zone confortable : ${humidityProfile.idealMin}-${humidityProfile.idealMax}%. ${advice}`;
  }
}

// Anti-spam intelligent :
// - critique : rappel possible toutes les 6h
// - warning : rappel possible toutes les 12h
// - changement d'état : envoi immédiat
const lastHumAlertTs = staticData.last_humidity_alert_ts || 0;
const lastHumAlertKey = staticData.last_humidity_alert_key || '';
const currentHumAlertKey = `${humidityStatus}:${humiditySeverity}:${season}:${weatherMain}`;
const hoursSinceLastHumAlert = (Date.now() - lastHumAlertTs) / 1000 / 3600;
const cooldownHours = humiditySeverity === 'critical' ? 6 : 12;

if (alertMessage) {
  if (hoursSinceLastHumAlert >= cooldownHours || lastHumAlertKey !== currentHumAlertKey) {
    sendHumAlert = true;
    staticData.last_humidity_alert_ts = Date.now();
    staticData.last_humidity_alert_key = currentHumAlertKey;
  }
} else {
  staticData.last_humidity_alert_ts = 0;
  staticData.last_humidity_alert_key = '';
}

// ==============================
// 7. ANTI-SPAM
// ==============================

const nowTs = Date.now();
const lastUpdateTs = staticData.last_tado_update_ts || 0;
const minutesSinceLastUpdate = (nowTs - lastUpdateTs) / 1000 / 60;

const targetChangedEnough = Math.abs(target - currentSetpoint) >= MIN_DELTA_SETPOINT
  || (powerActuel === 'OFF' && targetMode !== 'MANUAL_OFF_RESPECTED');

const delayOk = minutesSinceLastUpdate >= MIN_DELAY_MINUTES;

let action = (targetChangedEnough && delayOk) ? 'UPDATE' : 'IGNORE';

if (targetMode === 'MANUAL_OFF_RESPECTED') {
  action = 'IGNORE';
}

// ==============================
// 8. SORTIE ET MÉMORISATION
// ==============================

staticData.script_turned_it_off = (targetMode === 'ECO_MIN' || target <= MODE_ECO_MIN);
staticData.script_last_mode = targetMode;
staticData.last_requested_target = target;
staticData.last_reason = reason;

return [{
  temp_interieure: tempInt,
  temp_exterieure: tempExt,
  humidite_interieure: humiditeInt,
  consigne_actuelle: currentSetpoint,
  cible: target,
  target_mode: targetMode,
  reason,
  action,
  delayOk,
  targetChangedEnough,
  sendHumAlert,
  alertMessage,
  window_open_detected: windowOpenDetected,
  debug_solaire: {
    soleil_face_fenetre: solarInfo.sunFacingWindow,
    nuages: `${cloudCover}%`,
    chauffage_solaire_actif: solarGainScore > 0.2,
    elevation: `${round1(solar.elevation)}°`,
    azimut: `${round1(solar.azimuth)}°`,
    gain_solaire_score: round1(solarGainScore),
    bonus_solaire_estime: round1(solarThermalBonus),
    coucher_soleil_proche: isSunsetApproaching,
    minutes_avant_coucher: Math.round(minutesBeforeSunset)
  },
  debug_thermique: {
    saison: season,
    week_end: weekend,
    presence: presence,
    phase_journee: phase,
    confort_cible: round1(dynamicComfort),
    temperature_effective: round1(effectiveIndoorTemp),
    tendance_deg_par_heure: round1(tempTrendPerHour)
  },
  debug_humidite: {
    statut: humidityStatus,
    severite: humiditySeverity,
    plage_ideale: `${humidityProfile.idealMin}-${humidityProfile.idealMax}%`,
    seuil_bas_warning: humidityProfile.warnLow,
    seuil_bas_critique: humidityProfile.criticalLow,
    seuil_haut_warning: humidityProfile.warnHigh,
    seuil_haut_critique: humidityProfile.criticalHigh,
