const config = $('Configuration Tado').first().json;

// 1. On demande à Tado d'ouvrir une session d'autorisation
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://login.tado.com/oauth2/device_authorize',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
  },
  body: `client_id=${encodeURIComponent(config.CLIENT_ID)}&scope=offline_access`,
});

// 2. L'arme secrète contre Telegram : on encode les tirets du bas en "%5F"
// pour qu'il ne les transforme pas en italique !
const lienParfait = `https://login.tado.com/oauth2/device?user%5Fcode=${response.user_code}&client%5Fid=${config.CLIENT_ID}`;

// 3. On sauvegarde dans la mémoire globale (au cas où)
staticData.tado_pending_device_code = response.device_code;
staticData.tado_pending_verification_url = lienParfait;
staticData.tado_device_code_created_at = Date.now();

// 4. On envoie les infos à Telegram ET au dernier nœud du workflow
return [{
  recovery_needed: true,
  verification_uri_complete: lienParfait, // Le lien encodé pour Telegram
  user_code: response.user_code,
  expires_in: response.expires_in,
  interval: response.interval,
  device_code: response.device_code // La donnée vitale pour le nœud d'échange final !
}];

const staticData = $getWorkflowStaticData('global');
const config = $('Configuration Tado').first().json;

// On va lire le code directement depuis le nœud qui l'a généré !
const deviceCode = $('Demander nouveau device code').first().json.device_code;

if (!deviceCode) {
  throw new Error('Aucun device_code trouvé dans le nœud précédent.');
}

const tokenResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://login.tado.com/oauth2/token',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
  },
  body: `client_id=${encodeURIComponent(config.CLIENT_ID)}&grant_type=urn:ietf:params:oauth:grant-type:device_code&device_code=${encodeURIComponent(deviceCode)}`,
});

if (!tokenResponse.refresh_token) {
  throw new Error("Aucun refresh token reçu. L'autorisation n'a peut-être pas encore été validée sur le téléphone.");
}

// On sauvegarde enfin les tokens finaux dans la mémoire globale pour les prochains mois !
staticData.tado_access_token = tokenResponse.access_token;
staticData.tado_refresh_token = tokenResponse.refresh_token;

return [{
  auth_ok: true,
  access_token: tokenResponse.access_token,
  message: 'Nouveaux tokens Tado enregistrés avec succès !'
}];

