  const wait = (ms) => new Promise(resolve => setTimeout(resolve, ms));
  const exists = async (sel) => (await page.$(sel)) !== null;

  for (let i = 0; i < 4; i++) {
    await wait(2500);

    if (await exists('#loginId')) {
      await page.type('#loginId', email, {delay: 50});
      await page.type('#password', password, {delay: 50});
      await Promise.all([
        page.waitForNavigation({ waitUntil: 'networkidle2', timeout: 8000 }).catch(() => {}),
        page.click('form button.c-btn--primary')
      ]);
    } else if (await exists('#device-form')) {
      await Promise.all([
        page.waitForNavigation({ waitUntil: 'networkidle2', timeout: 8000 }).catch(() => {}),
        page.click('#device-form button.c-btn--primary')
      ]);
    } else {
      break;
    }
  }
  return { success: true };
};"
